# Category: oauth_security

from flask import Flask, request, jsonify
from flask_oauthlib.provider import OAuth2Provider

app = Flask(__name__)
oauth = OAuth2Provider(app)

auth_codes = {}

@oauth.token_request
def token_request():
    code = request.form.get('code')
    user_id = auth_codes.get(code)
    if user_id:
        return jsonify({'access_token': user_id}), 200
    return jsonify({'error': 'invalid_grant'}), 400

@oauth.authorize_request
def authorize_request():
    return jsonify({'code': request.args.get('code')}), 200

@app.route('/authorize')
def authorize():
    user_id = request.args.get('user_id')
    code = request.args.get('code')
    auth_codes[code] = user_id
    return jsonify({'redirect_uri': '/callback'}), 200

@app.route('/callback')
def callback():
    return jsonify({'access_token': auth_codes[request.args.get('code')]}), 200

if __name__ == '__main__':
    app.run(debug=True)